def pattern_132(nums):
    """
    Verilen bir tamsayı dizisinde 132 desenini arayın.

    132 deseni, dizide i < j < k olacak şekilde nums[i] < nums[k] < nums[j] koşulunu sağlayan üç tamsayı nums[i], nums[j] ve nums[k]'dan oluşan bir alt dizidir.

    Args:
      nums: Tamsayılardan oluşan bir liste.

    Returns:
      Dizide 132 deseni varsa True, yoksa False.
    """

    if len(nums) < 3:
        return False

    min_arr = [nums[0]]
    for i in range(1, len(nums)):
        min_arr.append(min(min_arr[-1], nums[i]))

    stack = []
    for j in range(len(nums) - 1, -1, -1):
        if nums[j] > min_arr[j]:
            while stack and stack[-1] <= min_arr[j]:
                stack.pop()
            if stack and stack[-1] < nums[j]:
                return True
            stack.append(nums[j])

    return False
